7	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
8	    let mut builder = GlobSetBuilder::new();
9	    for pat in patterns {
10	        builder.add(Glob::new(pat)?);
11	    }
12	    builder.build()
13	}
14	
15	pub fn is_rust_file(path: &Path) -> bool {
16	    path.extension().and_then(|e| e.to_str()) == Some("rs")
17	}
18	
19	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
20	    if exclude_set.is_empty() {
21	        return false;
22	    }
23	    exclude_set.is_match(path)
24	}
25	
26	pub fn should_process_entry(e: &walkdir::DirEntry, exclude_set: &GlobSet) -> bool {
27	    let ep = e.path();
28	    !should_skip(ep, exclude_set) && e.file_type().is_file() && is_rust_file(ep)
29	}
30	
31	pub fn collect_all_functions(
32	    paths: &[String],
33	    exclude_set: &GlobSet,
34	) -> (Vec<FunctionInfo>, Vec<String>) {
35	    let mut functions: Vec<FunctionInfo> = Vec::new();
36	    let mut errors: Vec<String> = Vec::new();
37	    for path_str in paths {
38	        let path = Path::new(path_str);
39	        if !path.exists() {
40	            errors.push(format!("path does not exist: {}", path_str));
41	        } else {
42	            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
43	        }
44	    }
45	    (functions, errors)
46	}
47	
48	pub fn collect_functions_from_path(
49	    path: &Path,
50	    exclude_set: &GlobSet,
51	    functions: &mut Vec<FunctionInfo>,
52	    errors: &mut Vec<String>,
53	) {
54	    if path.is_file() {
55	        collect_from_single_file(path, exclude_set, functions, errors);
56	    } else {
57	        collect_from_directory(path, exclude_set, functions, errors);
58	    }
59	}
60	
61	pub fn collect_from_single_file(
62	    path: &Path,
63	    exclude_set: &GlobSet,
64	    functions: &mut Vec<FunctionInfo>,
65	    errors: &mut Vec<String>,
66	) {
67	    if !should_skip(path, exclude_set) && is_rust_file(path) {
68	        process_file(path, functions, errors);
69	    }
70	}
71	
72	pub fn collect_from_directory(
73	    path: &Path,
74	    exclude_set: &GlobSet,
75	    functions: &mut Vec<FunctionInfo>,
76	    errors: &mut Vec<String>,
77	) {
78	    for entry in WalkDir::new(path).sort_by_file_name() {
79	        match entry {
80	            Ok(e) if should_process_entry(&e, exclude_set) => {
81	                process_file(e.path(), functions, errors);
82	            }
83	            Ok(_) => {}
84	            Err(err) => {
85	                errors.push(format!("walk error: {}", err));
86	            }
87	        }
88	    }
89	}
90	
91	pub fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
92	    let source = match std::fs::read_to_string(path) {
93	        Ok(s) => s,
94	        Err(e) => {
95	            errors.push(format!("cannot read {}: {}", path.display(), e));
96	            return;
97	        }
98	    };
99	
100	    match parse_source_tree(&source) {
101	        Ok(tree) => {
102	            let file_str = path.to_string_lossy().to_string();
103	            extract_functions(tree.root_node(), &source, &file_str, functions);
104	        }
105	        Err(msg) => {
106	            errors.push(format!("{} in {}", msg, path.display()));
107	        }
108	    }
109	}
110	
111	pub fn collect_rust_files(paths: &[String]) -> Vec<PathBuf> {
112	    let mut files = Vec::new();
113	    for p in paths {
114	        let path = Path::new(p);
115	        if path.is_file() {
116	            files.push(path.to_path_buf());
117	        } else {
118	            for entry in WalkDir::new(path).sort_by_file_name().into_iter().flatten() {
119	                if entry.file_type().is_file()
120	                    && entry.path().extension().and_then(|x| x.to_str()) == Some("rs")
121	                {
122	                    files.push(entry.path().to_path_buf());
123	                }
124	            }
125	        }
126	    }
127	    files
128	}
