115	fn function_with_exact_lines(lines: usize, nodes: usize) -> String {
116	    if nodes < 20 {
117	        // Need a function with < 20 AST nodes in our counting scheme.
118	        // Empirically: a 5-line split signature has 19 nodes, which is below min_nodes=20.
119	        // This function also passes min_lines=4 (5 lines >= 4).
120	        return "pub fn fixture_fn(\n    x: i32,\n) -> i32 {\n    x\n}\n".to_string();
121	    }
122	
123	    // For lines < 4 (below min_lines=4 default), generate a function that spans exactly `lines` lines.
124	    // Tree-sitter: opening line + body lines + closing line = total.
125	    let body_content = if lines <= 2 {
126	        "    0\n".to_string()
127	    } else {
128	        let inner = lines - 2;
129	        let mut s = String::new();
130	        for i in 0..(inner.saturating_sub(1)) {
131	            s.push_str(&format!("    let _v{} = {};\n", i, i));
132	        }
133	        s.push_str("    0\n");
134	        s
135	    };
136	    format!("pub fn fixture_fn(x: i32, y: i32) -> i32 {{\n{}}}\n", body_content)
137	}
