448	    let tokens: Vec<&str> = args_str.split_whitespace().collect();
449	    let mut result = Vec::new();
450	    let mut skip_next = false;
451	    for (i, tok) in tokens.iter().enumerate() {
452	        if skip_next {
453	            skip_next = false;
454	            result.push(tok.to_string());
455	            continue;
456	        }
457	        if tok.starts_with("--") || tok.starts_with('-') {
458	            if VALUE_OPTIONS.contains(tok) {
459	                skip_next = true;
460	            }
461	            result.push(tok.to_string());
462	        } else if let Some(ref r) = root {
463	            let p = Path::new(tok);
464	            if p.is_absolute() {
465	                result.push(tok.to_string());
466	            } else {
467	                result.push(Path::new(r).join(tok).to_string_lossy().to_string());
468	            }
469	        } else {
470	            result.push(tok.to_string());
471	        }
472	        let _ = i;
473	    }
474	    result
475	}
