pub struct PairEndpoint {
    pub file: String,
    pub start_line: usize,
    pub end_line: usize,
    pub nodes: usize,
}

#[derive(Debug, Clone, Serialize)]
pub struct DuplicatePair {
    pub score: f64,
    pub left: PairEndpoint,
    pub right: PairEndpoint,
}

pub struct Config {
    pub threshold: f64,
    pub min_lines: usize,
    pub min_nodes: usize,
    pub format: OutputFormat,
    pub excludes: Vec<String>,
}

