    fn default() -> Self {
        Config {
            threshold: 0.82,
            min_lines: 4,
            min_nodes: 20,
            format: OutputFormat::Text,
            excludes: vec![],
        }
    }
}

pub enum OutputFormat {
    Text,
    Json,
}

