    if is_builtin_excluded(ep) {
        return false;
    }
    if !e.file_type().is_file() {
        return true; // dirs handled by filter_entry via is_builtin_excluded
    }
    !should_skip(ep, exclude_set) && is_rust_file(ep) && !is_git_ignored(ep)
}

pub fn collect_all_functions(
    paths: &[String],
    exclude_set: &GlobSet,
) -> (Vec<FunctionInfo>, Vec<String>) {
    let mut functions: Vec<FunctionInfo> = Vec::new();
    let mut errors: Vec<String> = Vec::new();
    for path_str in paths {
        let path = Path::new(path_str);
        if !path.exists() {
            errors.push(format!("path does not exist: {}", path_str));
        } else {
            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
        }
    }
    (functions, errors)
}

pub fn collect_functions_from_path(
    path: &Path,
    exclude_set: &GlobSet,
    functions: &mut Vec<FunctionInfo>,
    errors: &mut Vec<String>,
) {
    if path.is_file() {
        collect_from_single_file(path, exclude_set, functions, errors);
    } else {
        collect_from_directory(path, exclude_set, functions, errors);
    }
}

pub fn collect_from_single_file(
    path: &Path,
    exclude_set: &GlobSet,
    functions: &mut Vec<FunctionInfo>,
    errors: &mut Vec<String>,
) {
    if is_builtin_excluded(path) {
        return;
    }
    if !should_skip(path, exclude_set) && is_rust_file(path) && !is_git_ignored(path) {
        process_file(path, functions, errors);
    }
}

pub fn collect_from_directory(
    path: &Path,
    exclude_set: &GlobSet,
    functions: &mut Vec<FunctionInfo>,
    errors: &mut Vec<String>,
) {
    for entry in WalkDir::new(path)
        .sort_by_file_name()
        .into_iter()
        .filter_entry(|e| {
            if e.file_type().is_dir() {
                !is_builtin_excluded(e.path())
            } else {
                true
            }
        })
    {
        match entry {
            Ok(e) if e.file_type().is_file() => {
                let ep = e.path();
                if is_rust_file(ep) && !should_skip(ep, exclude_set) && !is_git_ignored(ep) {
                    process_file(ep, functions, errors);
                }
            }
            Ok(_) => {}
            Err(err) => {
                errors.push(format!("walk error: {}", err));
            }
        }
    }
}

