pub fn is_git_ignored(path: &Path) -> bool {
    let abs = match path.canonicalize() {
        Ok(p) => p,
        Err(_) => return false,
    };
    let parent = match abs.parent() {
        Some(p) => p,
        None => return false,
    };
    let output = Command::new("git")
        .args(["-C", &parent.to_string_lossy(), "check-ignore", "--", &abs.to_string_lossy()])
        .output();
    match output {
        Ok(o) => o.status.code() == Some(0),
        Err(_) => false,
    }
}

pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
    let mut builder = GlobSetBuilder::new();
    for pat in patterns {
        builder.add(Glob::new(pat)?);
    }
    builder.build()
}

