145	pub fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
146	    let source = match std::fs::read_to_string(path) {
147	        Ok(s) => s,
148	        Err(e) => {
149	            errors.push(format!("cannot read {}: {}", path.display(), e));
150	            return;
151	        }
152	    };
153	
154	    match parse_source_tree(&source) {
155	        Ok(tree) => {
156	            let file_str = path.to_string_lossy().to_string();
157	            extract_functions(tree.root_node(), &source, &file_str, functions);
158	        }
159	        Err(msg) => {
160	            errors.push(format!("{} in {}", msg, path.display()));
161	        }
162	    }
163	}
